class Solution:
    def longestDecomposition(self, text: str) -> int:
        n = len(text)
        left, right = 0, n - 1
        k = 0
        while left <= right:
            if text[left] == text[right]:
                k += 1
                left += 1
                right -= 1
            else:
                break
        return k + 1
